                </button>
              </div>
              <div class="price-estimate-summary">
                <strong>{{ formatMRGFromCents(priceEvaluation.suggested_price_cents) }}</strong>
                <span>{{ formatMRGFromCents(priceEvaluation.suggested_range.low_cents) }} - {{ formatMRGFromCents(priceEvaluation.suggested_range.high_cents) }}</span>
              </div>
              <div class="price-breakdown-grid">
                <article v-for="item in priceEvaluation.breakdown.slice(0, 4)" :key="item.category">
                  <strong>{{ item.category }}</strong>
                  <span>{{ formatMRGFromCents(item.amount_cents) }}</span>
                  <small>{{ item.reason }}</small>
                </article>
              </div>
              <p v-if="priceEvaluation.risks?.length">{{ priceEvaluation.risks[0] }}</p>
            </section>

            <p v-if="priceEvaluationError" class="project-payment-error full">{{ priceEvaluationError }}</p>

            <section class="wizard-section full timeline-box" :class="{ invalid: projectFieldError('startDate') || projectFieldError('deadline') || projectFieldError('timeline') }">
              <div class="wizard-section-title">
                <strong>Timeline</strong>
                <small>When should this project be completed?</small>
              </div>
              <div class="timeline-grid">
                <label class="wizard-field" :class="{ invalid: projectFieldError('startDate') }">
                  <span>Start date</span>
                  <input v-model="projectSetupForm.startDate" type="date" :aria-invalid="Boolean(projectFieldError('startDate'))" @blur="markProjectFieldTouched('startDate')" />
                  <p v-if="projectFieldError('startDate')" class="wizard-field-error">{{ projectFieldError('startDate') }}</p>
                </label>
                <label class="wizard-field" :class="{ invalid: projectFieldError('deadline') || projectFieldError('timeline') }">
                  <span>Deadline</span>
                  <input v-model="projectSetupForm.deadline" type="date" :aria-invalid="Boolean(projectFieldError('deadline') || projectFieldError('timeline'))" @blur="markProjectFieldTouched('deadline')" />
                  <p v-if="projectFieldError('deadline')" class="wizard-field-error">{{ projectFieldError('deadline') }}</p>
                  <p v-else-if="projectFieldError('timeline')" class="wizard-field-error">{{ projectFieldError('timeline') }}</p>
                </label>
                <div class="duration-ring">
                  <strong>{{ projectDurationDays || '--' }}</strong>
                  <small>days</small>
                </div>
              </div>
            </section>

            <section class="wizard-section full">
              <div class="wizard-section-title">
