                <SendHorizontal v-if="projectWizardStep === 4" :size="15" />
                <ArrowRight v-else :size="15" />
              </button>
            </div>
          </footer>
        </article>

        <article v-else-if="projectWizardStage === 'funding'" class="wizard-card funding-panel">
