              <small>Add funds to your escrow to get tokens and attract top talent.</small>
            </div>
            <div class="funding-amount-grid">
              <button
                v-for="option in fundingAmountOptions"
                :key="option.amount"
                :class="{ selected: Number(projectFundingAmount) === option.amount }"
                class="funding-amount-card"
                type="button"
                @click="projectFundingAmount = option.amount"
              >
                <strong>{{ formatMoney(option.amount) }}</strong>
                <small>{{ formatMRG(option.tokens) }}</small>
                <span v-if="option.popular">Popular</span>
              </button>
            </div>
            <label class="wizard-field full" :class="{ invalid: projectFundingFieldError('amount') }">
              <span>Custom amount (USD)</span>
              <input v-model.number="projectFundingAmount" type="number" min="100" step="100" />
            </label>
            <p v-if="projectFundingFieldError('amount')" class="wizard-field-error">{{ projectFundingFieldError('amount') }}</p>
            <div class="token-receipt">
              <span>You will receive</span>
              <strong>{{ projectTokenAmountLabel }}</strong>
              <small>1 USD = {{ TOKEN_RATE_PER_USD }} {{ tokenSymbol }}</small>
            </div>
          </section>

          <section class="wizard-section full" :class="{ invalid: projectFundingFieldError('paymentMethod') }">
            <div class="wizard-section-title">
              <strong>2. Payment method</strong>
              <small>Choose your preferred payment method.</small>
            </div>
            <div class="payment-choice-grid">
              <button
                v-for="method in paymentMethodOptions"
                :key="method.label"
                :class="{ selected: projectPaymentMethod === method.label }"
                class="select-tile horizontal rich"
                type="button"
                @click="projectPaymentMethod = method.label"
              >
                <component :is="method.icon" :size="18" />
                <span>
                  <strong>{{ method.label }}</strong>
                  <small>{{ method.caption }}</small>
                </span>
              </button>
            </div>
            <p v-if="projectFundingFieldError('paymentMethod')" class="wizard-field-error payment-method-error">
              {{ projectFundingFieldError('paymentMethod') }}
            </p>
            <div v-if="projectPaymentMethod === 'Credit / Debit card'" class="card-input-grid">
              <label class="wizard-field full" :class="{ invalid: projectFundingFieldError('cardNumber') }">
                <span>Card number</span>
                <input v-model.trim="projectCardForm.cardNumber" autocomplete="cc-number" inputmode="numeric" placeholder="4242 4242 4242 4242" />
                <p v-if="projectFundingFieldError('cardNumber')" class="wizard-field-error">{{ projectFundingFieldError('cardNumber') }}</p>
              </label>
              <label class="wizard-field" :class="{ invalid: projectFundingFieldError('cardExpiry') }">
                <span>Expiry date</span>
                <input v-model.trim="projectCardForm.expiry" autocomplete="cc-exp" inputmode="numeric" placeholder="MM / YY" />
                <p v-if="projectFundingFieldError('cardExpiry')" class="wizard-field-error">{{ projectFundingFieldError('cardExpiry') }}</p>
              </label>
              <label class="wizard-field" :class="{ invalid: projectFundingFieldError('cardCvc') }">
                <span>CVC</span>
                <input v-model.trim="projectCardForm.cvc" autocomplete="cc-csc" inputmode="numeric" placeholder="CVC" />
                <p v-if="projectFundingFieldError('cardCvc')" class="wizard-field-error">{{ projectFundingFieldError('cardCvc') }}</p>
              </label>
              <label class="wizard-field" :class="{ invalid: projectFundingFieldError('cardholderName') }">
                <span>Cardholder name</span>
                <input v-model.trim="projectCardForm.cardholderName" autocomplete="cc-name" placeholder="Name on card" />
                <p v-if="projectFundingFieldError('cardholderName')" class="wizard-field-error">{{ projectFundingFieldError('cardholderName') }}</p>
              </label>
            </div>
            <div v-else-if="projectPaymentMethod === 'USDC'" class="payment-reference-box">
              <label class="wizard-field full" :class="{ invalid: projectFundingFieldError('cryptoReference') }">
                <span>Solana signature</span>
                <input v-model.trim="projectCryptoReference" autocomplete="off" placeholder="Paste confirmed Solana signature" />
                <p v-if="projectFundingFieldError('cryptoReference')" class="wizard-field-error">{{ projectFundingFieldError('cryptoReference') }}</p>
              </label>
              <p>
                Send the exact amount to the configured MergeOS Solana receiver, then paste the confirmed signature here.
              </p>
            </div>
            <div v-else class="payment-reference-box">
              <strong>PayPal checkout</strong>
              <p>MergeOS will create a PayPal order and return here to capture the approved payment.</p>
            </div>
          </section>

          <footer class="funding-actions">
            <span><Lock :size="14" /> Your payment is secure and encrypted.</span>
            <div>
              <small>Total to pay</small>
              <strong>{{ projectFundingAmountLabel }}</strong>
