                </li>
              </ul>
              <p v-else>{{ projectDeliverablesPlaceholder }}</p>
            </section>

            <section class="project-preview-section">
              <h3>
                <ShieldCheck :size="17" />
                Requirements
              </h3>
              <ul v-if="projectPreviewRequirements.length">
                <li v-for="requirement in projectPreviewRequirements" :key="requirement">
                  <CheckCircle2 :size="14" />
                  {{ requirement }}
                </li>
              </ul>
              <p v-else>No additional constraints.</p>
            </section>

            <section class="project-preview-section">
              <h3>
                <CircleDollarSign :size="17" />
                Budget and escrow
              </h3>
              <dl>
                <div>
                  <dt>Budget</dt>
                  <dd>{{ projectBudgetRangeLabel }}</dd>
                </div>
                <div>
                  <dt>Platform fee</dt>
                  <dd>{{ formatMRG(projectPlatformFeeLow) }} - {{ formatMRG(projectPlatformFeeHigh) }}</dd>
                </div>
                <div>
                  <dt>Escrow fee</dt>
                  <dd>{{ formatMRG(projectEscrowFeeLow) }} - {{ formatMRG(projectEscrowFeeHigh) }}</dd>
                </div>
                <div class="strong-row">
                  <dt>Estimated total</dt>
                  <dd>{{ projectEstimatedRangeLabel }}</dd>
                </div>
              </dl>
            </section>

            <section class="project-preview-section">
              <h3>
                <Bot :size="17" />
                Delivery lane
              </h3>
              <dl>
                <div>
                  <dt>Funding</dt>
                  <dd>{{ projectSetupForm.fundingMethod }}</dd>
                </div>
                <div>
                  <dt>Visibility</dt>
                  <dd>{{ projectSetupForm.visibility }}</dd>
                </div>
                <div>
                  <dt>AI agents</dt>
                  <dd>{{ projectSetupForm.allowAgents ? 'Allowed' : 'Disabled' }}</dd>
                </div>
                <div>
                  <dt>References</dt>
                  <dd>{{ referenceAttachments.length ? `${referenceAttachments.length} file${referenceAttachments.length === 1 ? '' : 's'}` : 'None' }}</dd>
                </div>
              </dl>
            </section>

            <section v-if="referenceAttachments.length" class="project-preview-section wide">
              <h3>
                <UploadCloud :size="17" />
                Reference files
              </h3>
              <div class="project-preview-files">
                <span v-for="attachment in referenceAttachments" :key="attachment.id">
                  <FileCheck2 :size="14" />
                  {{ attachment.original_name }}
                </span>
              </div>
            </section>
          </div>
        </div>

        <footer class="project-preview-actions">
          <button class="secondary-button compact" type="button" @click="editProjectPreviewStep(2)">
            <PenLine :size="15" />
