              </div>

              <article v-else class="notification-dropdown-empty">
                <strong>{{ dashboardNotificationsLoading ? 'Loading notifications...' : 'No notifications yet' }}</strong>
                <p>{{ dashboardNotificationsLoading ? 'Fetching delivery records.' : dashboardNotificationsError || 'Project updates will appear here.' }}</p>
              </article>

              <footer class="notification-dropdown-actions">
                <button type="button" @click="openDashboardNotificationCenter">View all</button>
                <button v-if="dashboardNotificationCount > 0" type="button" @click="markAllNotificationsReadFromMenu">
                  Mark all read
                </button>
              </footer>
            </section>
          </Teleport>
          <button class="primary-button compact" type="button" @click="openProjectWizard">
            <Plus :size="16" />
