                <div class="worker-audit-flags">
                  <span v-for="flag in workerAuditFlagRows" :key="flag.label" :class="flag.tone">
                    {{ flag.label }}
                  </span>
                </div>
              </section>

              <section class="dash-card live-pr-board">
                <div class="card-title-row">
                  <div>
                    <h2>Claimed Tasks</h2>
                    <p>Claimed, submitted, and paid work matched to your wallet or GitHub identity.</p>
                  </div>
                  <button type="button" @click="loadWorkerDashboardData">Refresh</button>
                </div>
                <div v-if="workerClaimedTaskRows.length" class="dash-pr-list">
                  <article v-for="task in workerClaimedTaskRows" :key="task.id" class="dash-pr-row">
                    <span class="contributor-avatar">{{ task.initials }}</span>
                    <div class="dash-pr-main">
                      <strong>#{{ task.issueNumber }} {{ task.title }}</strong>
                      <small>{{ task.acceptance }}</small>
                      <span>{{ task.project }}</span>
                    </div>
                    <div class="dash-pr-stat">
                      <strong>{{ task.reward }}</strong>
                      <small>Reward</small>
                    </div>
                    <div class="dash-pr-stat positive">
                      <strong>{{ task.kind }}</strong>
                      <small>Worker</small>
                    </div>
                    <div class="dash-pr-stat negative">
                      <strong>{{ task.when }}</strong>
                      <small>{{ task.whenLabel }}</small>
                    </div>
                    <div class="dash-pr-actions">
                      <b :class="task.statusTone">{{ task.status }}</b>
                      <a v-if="task.reviewURL" :href="task.reviewURL" target="_blank" rel="noreferrer">
                        <Link2 :size="12" />
                        Evidence
                      </a>
                      <button
                        v-if="task.canSubmitReview"
                        type="button"
                        :disabled="reviewSubmittingTaskID === task.id"
                        @click="toggleTaskReviewSubmission(task)"
                      >
                        <SendHorizontal :size="12" />
                        {{ task.reviewOpen ? 'Close' : 'Submit' }}
                      </button>
                    </div>
                    <form v-if="task.reviewOpen" class="task-review-panel" @submit.prevent="submitTaskReview(task)">
                      <div v-if="taskReviewErrorList(task).length" class="task-review-errors" role="alert">
                        <strong>Fix review evidence</strong>
                        <ul>
                          <li v-for="item in taskReviewErrorList(task)" :key="item.field">{{ item.message }}</li>
                        </ul>
                      </div>
                      <label :class="{ invalid: taskReviewFieldError(task, 'pullRequestURL') }">
                        <span>Pull request URL</span>
                        <input
                          v-model.trim="task.reviewDraft.pullRequestURL"
                          type="url"
                          :aria-invalid="Boolean(taskReviewFieldError(task, 'pullRequestURL'))"
                          placeholder="https://github.com/org/repo/pull/12"
                          @input="clearTaskReviewFieldError(task, 'pullRequestURL')"
                        />
                        <small v-if="taskReviewFieldError(task, 'pullRequestURL')">{{ taskReviewFieldError(task, 'pullRequestURL') }}</small>
                      </label>
                      <label :class="{ invalid: taskReviewFieldError(task, 'evidenceURL') }">
                        <span>Evidence URL</span>
                        <input
                          v-model.trim="task.reviewDraft.evidenceURL"
                          type="url"
                          :aria-invalid="Boolean(taskReviewFieldError(task, 'evidenceURL'))"
                          placeholder="https://preview.example.com/evidence"
                          @input="clearTaskReviewFieldError(task, 'evidenceURL')"
                        />
                        <small v-if="taskReviewFieldError(task, 'evidenceURL')">{{ taskReviewFieldError(task, 'evidenceURL') }}</small>
                      </label>
                      <label class="wide" :class="{ invalid: taskReviewFieldError(task, 'notes') }">
                        <span>Review notes</span>
                        <textarea
                          v-model.trim="task.reviewDraft.notes"
                          rows="3"
                          :aria-invalid="Boolean(taskReviewFieldError(task, 'notes'))"
                          placeholder="Tests, preview, deployment, and risk notes"
                          @input="clearTaskReviewFieldError(task, 'notes')"
                        ></textarea>
                        <small v-if="taskReviewFieldError(task, 'notes')">{{ taskReviewFieldError(task, 'notes') }}</small>
                      </label>
                      <button type="submit" :disabled="reviewSubmittingTaskID === task.id">
                        <SendHorizontal :size="13" />
                        {{ reviewSubmittingTaskID === task.id ? 'Submitting' : 'Submit review' }}
                      </button>
                    </form>
                  </article>
                </div>
                <article v-else class="dash-empty-state compact">
