                    <button type="button" @click="openDashboardSection('bounties')">
                      <Compass :size="13" />
                      Open Bounties
                    </button>
                    <button type="button" @click="loadWorkerDashboardData">
                      <RefreshCw :size="13" />
                      Refresh
                    </button>
                  </div>
                </article>
              </section>

