                      </button>
                      <button type="button" @click="loadWorkerDashboardData">
                        <RefreshCw :size="13" />
                        Refresh
                      </button>
                    </div>
                  </article>
                </article>

                <article class="dash-card worker-proposals-card">
                  <div class="card-title-row">
