                          <a v-for="context in proposal.contextRows" :key="context.key" :href="context.url" target="_blank" rel="noreferrer">
                            {{ context.label }}
                          </a>
                        </div>
                        <ol v-if="proposal.runbookRows.length" class="worker-claim-runbook" aria-label="Worker claim runbook">
                          <li v-for="step in proposal.runbookRows" :key="step.key">
                            <b>{{ step.step }}</b>
                            <span>{{ step.label }}</span>
                            <small>{{ step.meta }}</small>
                          </li>
                        </ol>
                        <div v-if="proposal.evidenceRows.length || proposal.payloadRows.length" class="worker-claim-packet" aria-label="Worker claim packet">
                          <span v-for="payload in proposal.payloadRows" :key="payload.label">
                            <b>{{ payload.label }}</b>
                            <small>{{ payload.value }}</small>
                          </span>
                          <span v-for="evidence in proposal.evidenceRows" :key="evidence">
                            <b>Evidence</b>
                            <small>{{ evidence }}</small>
                          </span>
                        </div>
                        <div v-if="proposal.warningRows.length" class="worker-claim-warnings">
