              <strong>{{ dashboardToolSectionView.title }}</strong>
            </div>

            <section class="dash-project-header dashboard-tool-header">
                <div class="dash-project-title">
                  <span class="project-photo payment-photo">
                    <component :is="dashboardToolSectionView.icon" :size="18" />
                  </span>
                  <div>
                    <h1>{{ dashboardToolSectionView.title }}</h1>
                    <p>{{ dashboardToolSectionView.body }}</p>
                  </div>
                  <span :class="['live-badge', dashboardStatusClass(dashboardToolSectionView.status)]">{{ dashboardToolSectionView.status }}</span>
                </div>

                <div class="dash-project-actions">
                  <button type="button" @click="refreshDashboardToolSection">
                    <RefreshCw :size="15" />
                    Refresh
