                    </button>
                    <button type="button" @click="openProjectWizard">
                      <Plus :size="13" />
                      Start Project
                    </button>
                    <button type="button" @click="openDashboardSection('repo-import')">
                      <UploadCloud :size="13" />
                      Import Repo
                    </button>
                    <button type="button" @click="refreshDashboardToolSection">
                      <RefreshCw :size="13" />
