                    <div class="agent-task-main">
                      <strong>{{ task.issue }} {{ task.title }}</strong>
                      <small>{{ task.project }} - {{ task.lane }} - {{ task.reward }}</small>
                      <p>{{ task.summary }}</p>
                      <em>{{ task.evidence }}</em>
                      <em v-if="task.nextAction">{{ task.nextAction }}</em>
