                        </button>
                      </div>
                      <div v-if="task.packetRows.length" class="agent-work-packet" aria-label="Agent work packet">
                        <span v-for="packet in task.packetRows" :key="packet.label">
                          <b>{{ packet.label }}</b>
                          <small>{{ packet.value }}</small>
                        </span>
                      </div>
                      <ol v-if="task.runbookRows.length" class="agent-runbook-strip" aria-label="Agent runbook">
                        <li v-for="step in task.runbookRows" :key="step.key">
                          <b>{{ step.step }}</b>
                          <span>{{ step.label }}</span>
                          <small>{{ step.method }} {{ step.endpoint }}</small>
                        </li>
                      </ol>
                    </div>
                    <b>{{ task.readiness }}</b>
