                      type="url"
                      placeholder="https://github.com/owner/repo"
                      @input="clearRepoImportFieldError('repoUrl')"
                      @keyup.enter="loadRepoIssues"
                    />
                    <small v-if="repoImportFieldError('repoUrl')" class="dashboard-tool-field-error">{{ repoImportFieldError('repoUrl') }}</small>
                  </label>
