                    </button>
                    <button type="button" @click="continueImportedRepoProject('estimate')">
                      <Calculator :size="13" />
                      Estimate Reward
                    </button>
                    <button type="button" @click="continueImportedRepoProject('funding')">
                      <CircleDollarSign :size="13" />
