                    <span>Released <strong>{{ formatMRGFromCents(dashboardLedgerPayoutCents || dashboardSpentCents) }}</strong></span>
                    <span>Remaining <strong>{{ formatMRGFromCents(dashboardRemainingCents) }}</strong></span>
