                      </button>
                      <button v-if="task.canRequestChanges" type="button" :disabled="requestingChangesTaskID === task.id" @click="requestTaskChanges(task)">
                        <RefreshCw :size="12" />
                        {{ requestingChangesTaskID === task.id ? 'Sending' : 'Changes' }}
                      </button>
                    </article>
                  </div>
                  <article v-else class="dash-empty-state compact">
                    <strong>No escrow task rows yet</strong>
                    <p>Task reserves appear after a funded project is split into delivery tasks.</p>
                    <div v-if="!dashboardSelectedProject" class="dashboard-tool-empty-actions compact">
                      <button
                        v-for="action in dashboardProjectBootstrapActions"
                        :key="action.label"
                        type="button"
                        :disabled="action.disabled"
                        @click="action.run()"
                      >
                        <component :is="action.icon" :size="13" />
                        {{ action.label }}
                      </button>
                    </div>
                  </article>
                </article>

                <article class="dash-card routing-board-card">
                  <div class="card-title-row">
