                  </span>
                </div>

                <div v-if="dashboardAutoReleaseControl.count" class="auto-release-command-panel" aria-label="Auto-release command packet">
                  <div class="auto-release-command-head">
                    <span>{{ dashboardAutoReleaseControl.count }} eligible</span>
                    <div>
                      <strong>{{ dashboardAutoReleaseControl.policy }}</strong>
                      <small>{{ dashboardAutoReleaseControl.summary }}</small>
                    </div>
                    <b>{{ dashboardAutoReleaseControl.command }}</b>
                  </div>
                  <div v-if="dashboardAutoReleaseControl.contextRows.length" class="auto-release-context-links">
                    <a v-for="context in dashboardAutoReleaseControl.contextRows" :key="context.key" :href="context.url" target="_blank" rel="noreferrer">
                      {{ context.label }}
                    </a>
                  </div>
                  <ol v-if="dashboardAutoReleaseControl.runbookRows.length" class="auto-release-runbook">
                    <li v-for="step in dashboardAutoReleaseControl.runbookRows" :key="step.key">
                      <span>{{ step.step }}</span>
                      <div>
                        <strong>{{ step.label }}</strong>
                        <small>{{ step.meta || step.purpose }}</small>
                      </div>
                      <b>{{ step.required ? 'Required' : 'Optional' }}</b>
                    </li>
                  </ol>
                  <div v-if="dashboardAutoReleaseControl.payloadRows.length" class="auto-release-payload-strip">
                    <span v-for="item in dashboardAutoReleaseControl.payloadRows" :key="item.label">
                      {{ item.label }}
                      <strong>{{ item.value }}</strong>
                    </span>
                  </div>
                </div>

                <div v-if="dashboardPullRequestRows.length" class="dash-pr-list">
                  <article v-for="pr in dashboardPullRequestRows" :key="pr.id" class="dash-pr-row pr-monitor-row">
                    <span class="contributor-avatar">{{ pr.initials }}</span>
                    <div class="dash-pr-main">
                      <strong>#{{ pr.issueNumber }} {{ pr.title }}</strong>
                      <small>{{ pr.acceptance }}</small>
                      <span>{{ pr.reference }}</span>
                      <span v-if="pr.releaseCommand">{{ pr.releaseCommand }}</span>
                      <span v-if="pr.autoReleaseCommand">{{ pr.autoReleaseCommand }}</span>
                    </div>
                    <div class="dash-pr-stat">
                      <strong>{{ pr.reward }}</strong>
                      <small>Reward</small>
                    </div>
                    <div class="dash-pr-stat positive">
                      <strong>{{ pr.worker }}</strong>
                      <small>Worker</small>
                    </div>
                    <div class="dash-pr-stat negative">
                      <strong>{{ pr.risk }}</strong>
                      <small>Risk</small>
                    </div>
                    <div class="dash-pr-actions">
                      <b :class="pr.statusClass">{{ pr.status }}</b>
                      <a v-if="pr.primaryURL" :href="pr.primaryURL" target="_blank" rel="noreferrer">
                        <GitPullRequest :size="12" />
                        {{ pr.primaryLabel }}
                      </a>
                      <a v-if="pr.evidenceURL && pr.evidenceURL !== pr.primaryURL" :href="pr.evidenceURL" target="_blank" rel="noreferrer">
                        <Link2 :size="12" />
                        Evidence
                      </a>
                      <button v-if="pr.rawContractReference" class="contract-ref-button" type="button" @click="copyContractReference(pr)">
                        <Hash :size="12" />
                        {{ pr.contractReference }}
                      </button>
                      <button
                        v-if="pr.canRelease"
                        type="button"
                        :disabled="releasingTaskID === pr.id"
                        @click="releaseTaskPayment(pr)"
                      >
                        <CircleDollarSign :size="12" />
                        {{ releasingTaskID === pr.id ? 'Releasing' : 'Release' }}
                      </button>
                      <button
                        v-if="pr.canRequestChanges"
                        type="button"
                        :disabled="requestingChangesTaskID === pr.id"
                        @click="requestTaskChanges(pr)"
                      >
                        <RefreshCw :size="12" />
                        {{ requestingChangesTaskID === pr.id ? 'Sending' : 'Changes' }}
                      </button>
                    </div>
                    <div v-if="pr.signals.length" class="pr-monitor-signals">
                      <span v-for="signal in pr.signals" :key="signal">{{ signal }}</span>
                    </div>
                  </article>
                </div>
                <article v-else class="dash-empty-state compact">
                  <strong>{{ dashboardPullRequestEmptyState.title }}</strong>
                  <p>{{ dashboardPullRequestEmptyState.body }}</p>
                  <div v-if="dashboardPullRequestEmptyActions.length" class="dashboard-tool-empty-actions">
                    <button
                      v-for="action in dashboardPullRequestEmptyActions"
                      :key="action.label"
                      type="button"
                      :disabled="action.disabled"
                      @click="action.run()"
                    >
                      <component :is="action.icon" :size="13" />
                      {{ action.label }}
                    </button>
                  </div>
                </article>
              </section>

              <section ref="dashboardTasksPanel" class="dash-card live-pr-board dashboard-focus-target" tabindex="-1">
                <div class="card-title-row">
                  <div>
                    <h2>Project Tasks</h2>
                    <p>Real tasks split from the funded project and loaded from the backend.</p>
                  </div>
                  <button type="button" @click="loadDashboardData">Refresh Tasks</button>
                </div>

                <div v-if="dashboardTaskRows.length" class="dash-pr-list">
                  <article v-for="task in dashboardTaskRows" :key="task.id" class="dash-pr-row">
                    <span class="contributor-avatar">{{ task.initials }}</span>
                    <div class="dash-pr-main">
                      <strong>#{{ task.issueNumber }} {{ task.title }}</strong>
                      <small>{{ task.acceptance }}</small>
                      <span>{{ task.reference }}</span>
                    </div>
                    <div class="dash-pr-stat">
                      <strong>{{ task.reward }}</strong>
                      <small>Reward</small>
                    </div>
                    <div class="dash-pr-stat positive">
                      <strong>{{ task.kind }}</strong>
                      <small>Worker</small>
                    </div>
                    <div class="dash-pr-stat negative">
                      <strong>{{ task.agent }}</strong>
                      <small>Agent</small>
                    </div>
                    <div class="dash-pr-actions">
                      <b :class="task.statusClass">{{ task.status }}</b>
                      <a v-if="task.reviewURL" :href="task.reviewURL" target="_blank" rel="noreferrer">
                        <Link2 :size="12" />
                        Evidence
                      </a>
                      <button
                        v-if="task.canRelease"
                        type="button"
                        :disabled="releasingTaskID === task.id"
                        @click="releaseTaskPayment(task)"
                      >
                        <CircleDollarSign :size="12" />
                        {{ releasingTaskID === task.id ? 'Releasing' : 'Release' }}
                      </button>
                      <button
                        v-if="task.canRequestChanges"
                        type="button"
                        :disabled="requestingChangesTaskID === task.id"
                        @click="requestTaskChanges(task)"
                      >
                        <RefreshCw :size="12" />
                        {{ requestingChangesTaskID === task.id ? 'Sending' : 'Changes' }}
                      </button>
                    </div>
                  </article>
                </div>
                <article v-else class="dash-empty-state compact">
                  <strong>{{ dashboardLoading ? 'Loading tasks...' : 'No tasks yet' }}</strong>
                  <p>{{ dashboardLoading ? 'Fetching your project task split.' : 'Fund a project to generate real tasks.' }}</p>
                  <div v-if="!dashboardLoading && !dashboardSelectedProject" class="dashboard-tool-empty-actions compact">
                    <button
                      v-for="action in dashboardProjectBootstrapActions"
                      :key="action.label"
                      type="button"
                      :disabled="action.disabled"
                      @click="action.run()"
                    >
                      <component :is="action.icon" :size="13" />
                      {{ action.label }}
                    </button>
                  </div>
                </article>

                <div class="watching-line">
                  <ListTodo :size="14" />
                  {{ dashboardTaskRows.length }} real tasks loaded
                </div>
              </section>
            </template>
          </template>
        </section>

        <aside class="dash-rail">
          <section class="dash-card rail-card wallet-summary-card">
            <div class="card-title-row">
              <h2>MRG Wallet</h2>
              <span class="recording-dot">Live</span>
            </div>
            <div class="wallet-address-box">
              <small>Wallet address</small>
              <strong>{{ user.wallet_address || 'Creating wallet...' }}</strong>
            </div>
            <div class="wallet-link-row">
              <span>{{ user.github_username ? `github:${user.github_username}` : 'GitHub not linked' }}</span>
            </div>
            <div class="wallet-action-row">
              <button class="rail-link-button" :disabled="!user.wallet_address" type="button" @click="openWalletOnScan(user.wallet_address)">
                View on Scan
              </button>
              <button class="rail-link-button" :disabled="authBusy || !githubOAuthReady" type="button" @click="startGitHubLogin">
                Link GitHub
              </button>
            </div>
            <form class="wallet-migration-form" @submit.prevent="submitWalletMigration">
              <div class="wallet-migration-grid">
                <label>
                  <span>Legacy chain</span>
                  <select v-model="walletMigrationForm.legacy_chain" :disabled="walletMigrationBusy">
                    <option value="trc20">TRC20 / TRON</option>
                    <option value="evm">EVM</option>
                  </select>
                </label>
                <label>
                  <span>Old wallet</span>
                  <input v-model.trim="walletMigrationForm.legacy_address" :disabled="walletMigrationBusy" placeholder="Paste old TRC20 or EVM wallet" autocomplete="off" />
                </label>
              </div>
              <button class="rail-link-button wallet-migration-submit" :disabled="walletMigrationBusy || !walletMigrationForm.legacy_address.trim()" type="submit">
                {{ walletMigrationBusy ? 'Migrating...' : 'Migrate to Solana' }}
              </button>
              <p v-if="walletMigrationError" class="wallet-migration-error">{{ walletMigrationError }}</p>
              <article v-if="walletMigrationResult" class="wallet-migration-result">
                <strong>{{ shortWallet(walletMigrationResult.target_address) }}</strong>
                <small>{{ walletMigrationResult.status }} / {{ walletMigrationResult.contract?.instruction }}</small>
              </article>
            </form>
          </section>

          <section ref="dashboardProjectListPanel" class="dash-card rail-card project-picker-card dashboard-focus-target" tabindex="-1">
            <div class="card-title-row">
              <h2>My Projects</h2>
              <span>{{ dashboardProjectList.length }}</span>
            </div>
            <div v-if="dashboardProjectList.length" class="dashboard-project-list">
              <button
                v-for="project in dashboardProjectList"
                :key="project.id"
                :class="{ active: project.id === dashboardSelectedProject?.id }"
                type="button"
                @click="selectDashboardProject(project.id)"
              >
                <span class="contributor-avatar">{{ initialsFor(project.title || project.company_name || 'MP') }}</span>
                <div>
                  <strong>{{ project.title }}</strong>
                  <small>{{ formatMRGFromCents(project.budget_cents) }} - {{ (project.tasks || []).length }} tasks</small>
                </div>
              </button>
            </div>
            <article v-else class="dash-empty-state compact">
              <strong>{{ dashboardLoading ? 'Loading projects...' : 'No projects found' }}</strong>
              <p>{{ dashboardLoading ? 'Syncing your workspace.' : 'Create and fund a project to populate this list.' }}</p>
              <div v-if="!dashboardLoading" class="dashboard-tool-empty-actions compact">
                <button
                  v-for="action in dashboardProjectBootstrapActions"
                  :key="action.label"
                  type="button"
                  :disabled="action.disabled"
                  @click="action.run()"
                >
                  <component :is="action.icon" :size="13" />
                  {{ action.label }}
                </button>
              </div>
            </article>
          </section>

          <section ref="dashboardActivityPanel" class="dash-card rail-card dashboard-focus-target" tabindex="-1">
            <div class="card-title-row">
              <h2>Live Activity</h2>
              <span class="recording-dot">Live</span>
            </div>
