              <article v-for="activity in dashboardActivityRows" :key="activity.key">
                <span :class="['activity-icon', activity.color]">
                  <component :is="activity.icon" :size="14" />
                </span>
                <div>
                  <strong>{{ activity.title }}</strong>
                  <small>{{ activity.time }}</small>
                </div>
              </article>
            </div>
            <article v-else class="dash-empty-state compact">
              <strong>No ledger activity</strong>
              <p>Project ledger entries will appear after funding.</p>
              <div class="dashboard-tool-empty-actions compact">
                <button type="button" @click="openPublicPage('ledger')">
                  <Link2 :size="13" />
                  Public Ledger
                </button>
                <button type="button" @click="openProjectWizard">
                  <Plus :size="13" />
                  Start Project
                </button>
              </div>
            </article>
            <button class="rail-link-button" type="button" @click="openPublicPage('ledger')">
              View ledger
            </button>
          </section>

          <section class="dash-card rail-card customer-protocol-card">
            <div class="card-title-row">
              <h2>Customer Protocol</h2>
              <span :class="['dashboard-status-pill', dashboardStatusClass(customerDashboardProtocolView.status)]">{{ customerDashboardProtocolView.status }}</span>
            </div>
            <div class="customer-protocol-meta">
              <strong>{{ customerDashboardProtocolView.version }}</strong>
              <small>{{ customerDashboardProtocolView.updated }}</small>
            </div>
            <div class="customer-protocol-grid" aria-label="Customer protocol counts">
              <span>
                <strong>{{ customerDashboardProtocolView.projects }}</strong>
                Projects
              </span>
              <span>
                <strong>{{ customerDashboardProtocolView.tasks }}</strong>
                Tasks
              </span>
              <span>
                <strong>{{ customerDashboardProtocolView.ledger }}</strong>
                Ledger
              </span>
            </div>
            <div v-if="customerDashboardSignals.length" class="customer-signal-list">
              <article v-for="signal in customerDashboardSignals.slice(0, 4)" :key="signal.id">
                <span :class="['notification-dot', signal.tone]" />
                <div>
                  <strong>{{ signal.title }}</strong>
                  <small>{{ signal.meta }}</small>
                </div>
              </article>
            </div>
            <article v-else class="dash-empty-state compact">
              <strong>No protocol signals</strong>
              <p>AI, deployment, task, and ledger signals will appear after project activity.</p>
              <div v-if="!dashboardSelectedProject" class="dashboard-tool-empty-actions compact">
                <button
                  v-for="action in dashboardProjectBootstrapActions"
                  :key="action.label"
                  type="button"
                  :disabled="action.disabled"
                  @click="action.run()"
                >
                  <component :is="action.icon" :size="13" />
                  {{ action.label }}
                </button>
              </div>
            </article>
          </section>

          <section class="dash-card rail-card workflow-pulse-card">
            <div class="card-title-row">
              <h2>Workflow Pulse</h2>
              <span :class="['dashboard-status-pill', dashboardStatusClass(dashboardWorkflowPulseView.status)]">{{ dashboardWorkflowPulseView.status }}</span>
            </div>
            <div class="ai-workflow-summary">
              <span><GitBranch :size="16" /></span>
              <div>
                <strong>{{ dashboardWorkflowPulseView.progress }}%</strong>
                <small>{{ dashboardWorkflowPulseView.body }}</small>
              </div>
            </div>
            <div v-if="dashboardWorkflowPulseError" class="deployment-error">{{ dashboardWorkflowPulseError }}</div>
            <div v-else-if="dashboardWorkflowPulseStages.length" class="ai-workflow-list">
              <article v-for="stage in dashboardWorkflowPulseStages" :key="stage.id">
                <span :class="['notification-dot', stage.tone]" />
                <div>
                  <strong>{{ stage.title }}</strong>
                  <small>{{ stage.body }}</small>
                </div>
                <b>{{ stage.status }}</b>
              </article>
            </div>
            <article v-else class="dash-empty-state compact">
              <strong>{{ dashboardWorkflowPulseLoading ? 'Loading pulse...' : 'No workflow pulse yet' }}</strong>
              <p>{{ dashboardWorkflowPulseLoading ? 'Syncing delivery stages.' : 'Select a project to inspect the delivery pulse.' }}</p>
              <div v-if="!dashboardWorkflowPulseLoading && !dashboardSelectedProject" class="dashboard-tool-empty-actions compact">
                <button
                  v-for="action in dashboardProjectBootstrapActions"
                  :key="action.label"
                  type="button"
                  :disabled="action.disabled"
                  @click="action.run()"
                >
                  <component :is="action.icon" :size="13" />
                  {{ action.label }}
                </button>
              </div>
            </article>
            <button class="rail-link-button" type="button" :disabled="dashboardWorkflowPulseLoading || !dashboardSelectedProject" @click="loadDashboardWorkflowPulseData(dashboardSelectedProject?.id)">
              Refresh pulse
            </button>
          </section>

          <section class="dash-card rail-card ai-workflow-card">
            <div class="card-title-row">
              <h2>AI Orchestration</h2>
              <span :class="['dashboard-status-pill', dashboardStatusClass(dashboardAIWorkflowView.status)]">{{ dashboardAIWorkflowView.status }}</span>
            </div>
            <div class="ai-workflow-summary">
              <span><Bot :size="16" /></span>
              <div>
                <strong>{{ dashboardAIWorkflowView.progress }}%</strong>
                <small>{{ dashboardAIWorkflowView.body }}</small>
              </div>
            </div>
            <div v-if="dashboardAIWorkflowError" class="deployment-error">{{ dashboardAIWorkflowError }}</div>
            <div v-else-if="dashboardAIWorkflowStages.length" class="ai-workflow-list">
              <article v-for="stage in dashboardAIWorkflowStages" :key="stage.id">
                <span :class="['notification-dot', stage.tone]" />
                <div>
                  <strong>{{ stage.title }}</strong>
                  <small>{{ stage.body }}</small>
                </div>
                <b>{{ stage.status }}</b>
              </article>
            </div>
            <article v-else class="dash-empty-state compact">
              <strong>{{ dashboardAIWorkflowLoading ? 'Loading workflow...' : 'No AI workflow yet' }}</strong>
              <p>{{ dashboardAIWorkflowLoading ? 'Syncing orchestration stages.' : 'Select a project to inspect AI routing.' }}</p>
              <div v-if="!dashboardAIWorkflowLoading && !dashboardSelectedProject" class="dashboard-tool-empty-actions compact">
                <button
                  v-for="action in dashboardProjectBootstrapActions"
                  :key="action.label"
                  type="button"
                  :disabled="action.disabled"
                  @click="action.run()"
                >
                  <component :is="action.icon" :size="13" />
                  {{ action.label }}
                </button>
              </div>
            </article>
            <button class="rail-link-button" type="button" :disabled="dashboardAIWorkflowLoading || !dashboardSelectedProject" @click="loadDashboardAIWorkflowData(dashboardSelectedProject?.id)">
              Refresh workflow
            </button>
          </section>

          <section ref="dashboardNotificationCenter" class="dash-card rail-card notification-center-card" tabindex="-1">
            <div class="card-title-row">
              <h2>Notifications</h2>
              <span>{{ dashboardNotificationCount }} new</span>
            </div>
            <div v-if="dashboardNotificationRows.length" class="notification-center-list">
              <article
                v-for="note in dashboardNotificationRows"
                :key="note.id"
                :class="{ 'is-unread': note.isUnread }"
                role="button"
                tabindex="0"
                @click="handleNotificationClick(note)"
                @keyup.enter="handleNotificationClick(note)"
              >
                <span :class="['notification-dot', note.tone, { 'unread-pulse': note.isUnread }]" />
                <div>
                  <strong>{{ note.subject }}</strong>
                  <p>{{ note.body }}</p>
                  <small>{{ note.meta }}</small>
                </div>
                <span v-if="note.isUnread" class="notification-new-badge" aria-label="Unread">New</span>
              </article>
            </div>
            <article v-else class="dash-empty-state compact">
              <strong>{{ dashboardNotificationsLoading ? 'Loading notifications...' : 'No notifications yet' }}</strong>
              <p>{{ dashboardNotificationsLoading ? 'Fetching delivery records.' : dashboardNotificationsError || 'Project updates and delivery notices will appear here.' }}</p>
            </article>
            <div class="notification-actions-row">
              <button class="rail-link-button" type="button" @click="loadDashboardNotifications">
                Refresh
              </button>
              <button v-if="dashboardNotificationCount > 0" class="rail-link-button" type="button" @click="markAllNotificationsRead">
                Mark all read
              </button>
            </div>
