            <strong>{{ lane.title }}</strong>
            <p>{{ lane.body }}</p>
            <small>{{ lane.value }}</small>
          </article>
        </section>

        <section class="contracts-content-grid">
          <div class="contracts-main-card">
            <div class="contracts-section-head">
              <div>
                <span class="marketplace-eyebrow">{{ publicContractsCopy.flowTitle }}</span>
