            <div class="contracts-proof-list">
              <article v-for="row in contractsProofRows" :key="row.label">
                <span :class="['ledger-economy-mini-icon', row.tone]">
                  <component :is="row.icon" :size="14" />
                </span>
                <div>
                  <strong>{{ row.label }}</strong>
                  <small>{{ row.value }}</small>
                </div>
                <button type="button" @click="copyContractsProofRow(row)">
                  <Link2 :size="12" />
                </button>
              </article>
            </div>
          </aside>
        </section>

        <section class="contracts-ledger-grid">
          <article class="contracts-ledger-panel">
            <div class="contracts-section-head compact">
              <div>
                <span class="marketplace-eyebrow">{{ publicContractsCopy.reserveTitle }}</span>
                <h2>{{ publicContractsCopy.reserveTitle }}</h2>
              </div>
              <small>{{ contractsReserveRows.length }}</small>
            </div>
            <p>{{ publicContractsCopy.reserveBody }}</p>
            <div v-if="contractsReserveRows.length" class="contracts-row-list">
              <article v-for="row in contractsReserveRows" :key="row.id">
                <span :class="['ledger-economy-mini-icon', row.tone]">
                  <component :is="row.icon" :size="14" />
                </span>
                <div>
                  <strong>{{ row.label }}</strong>
                  <small>{{ row.role }} - {{ row.count }}</small>
                </div>
                <b>{{ row.amount }}</b>
              </article>
            </div>
            <div v-else class="live-feed-state">{{ publicContractsCopy.noRows }}</div>
          </article>

          <article class="contracts-ledger-panel">
            <div class="contracts-section-head compact">
              <div>
                <span class="marketplace-eyebrow">{{ publicContractsCopy.flowTitle }}</span>
                <h2>{{ publicContractsCopy.flowTitle }}</h2>
              </div>
              <small>{{ ledgerEconomyFlowRows.length }}</small>
            </div>
            <p>{{ publicContractsCopy.flowBody }}</p>
            <div v-if="ledgerEconomyFlowRows.length" class="contracts-row-list">
              <article v-for="row in ledgerEconomyFlowRows" :key="row.type">
                <span :class="['ledger-economy-mini-icon', row.tone]">
                  <component :is="row.icon" :size="14" />
                </span>
                <div>
                  <strong>{{ row.label }}</strong>
                  <small>{{ row.countLabel }} - #{{ row.latestSequence }}</small>
                </div>
                <b>{{ row.amount }}</b>
              </article>
            </div>
            <div v-else class="live-feed-state">{{ publicContractsCopy.noRows }}</div>
          </article>

          <article class="contracts-ledger-panel">
            <div class="contracts-section-head compact">
              <div>
                <span class="marketplace-eyebrow">{{ publicContractsCopy.recentTitle }}</span>
                <h2>{{ publicContractsCopy.recentTitle }}</h2>
              </div>
              <button type="button" @click="openPublicPage('ledger')">
                {{ publicContractsCopy.openLedger }}
                <ArrowRight :size="12" />
              </button>
            </div>
            <p>{{ publicContractsCopy.recentBody }}</p>
            <div v-if="contractsRecentAnchors.length" class="contracts-row-list">
              <article v-for="row in contractsRecentAnchors" :key="row.key">
