                <Lock :size="16" />
              </button>
              <button class="primary-button large" type="submit" :disabled="presaleReservationBusy">
                {{ presaleReservationSubmitLabel }}
                <ArrowRight :size="16" />
              </button>
            </footer>
          </form>
