              <Download :size="13" />
            </a>
          </div>
          <div class="token-whitepaper-section-list">
            <article v-for="section in publicWhitepaperChapterSections" :key="section.title">
              <span>{{ section.kicker }}</span>
              <h3>{{ section.title }}</h3>
