              </span>
            </div>
            <p>{{ publicProtocolCopy.body }}</p>
            <div class="marketplace-actions">
              <button class="primary-button large" type="button" @click="openExternalURL(publicProtocolManifestPath)">
                {{ publicProtocolCopy.primaryAction }}
                <ArrowRight :size="16" />
              </button>
              <button class="secondary-button large" type="button" @click="copyProtocolManifestURL">
                {{ publicProtocolCopy.copyManifest }}
                <Link2 :size="16" />
              </button>
              <button class="secondary-button large" type="button" @click="openPublicPage('live')">
                {{ publicProtocolCopy.liveAction }}
                <Zap :size="16" />
              </button>
            </div>
          </div>

          <aside class="protocol-manifest-card" aria-label="Protocol manifest status">
            <div class="ledger-card-head">
