const ledgerProofSummary = computed(() => {
  const proof = ledgerProof.value || {};
  const entryCount = Number(proof.entry_count) || 0;
  const verifiedCount = Number(proof.verified_count) || 0;
  const brokenCount = Number(proof.broken_count) || 0;
  if (!entryCount) {
    return {
      status: 'empty',
      label: 'Awaiting first entry',
      body: 'The public proof manifest will publish a root hash after the first funded project.',
      verifiedLabel: '0/0',
    };
  }
  if (proof.valid) {
    return {
      status: 'valid',
      label: 'Hash chain valid',
      body: `${verifiedCount} ledger rows match their stored hashes and public redacted hash chain.`,
      verifiedLabel: `${verifiedCount}/${entryCount}`,
    };
  }
  return {
    status: 'invalid',
    label: 'Needs review',
    body: `${brokenCount || 'Some'} ledger rows failed hash-chain verification.`,
    verifiedLabel: `${verifiedCount}/${entryCount}`,
  };
});
const ledgerVerificationChecks = computed(() => [
  `${ledgerProofSummary.value.verifiedLabel} ledger rows verified`,
  `Root ${shortLedgerHash(ledgerProof.value?.root_hash)}`,
  `Public root ${shortLedgerHash(ledgerProof.value?.public_root_hash)}`,
  ledgerProofContractReference.value ? `Contract ${shortLedgerHash(ledgerProofContractReference.value)}` : 'Contract anchors pending',
]);
const ledgerTrendingProjects = computed(() => {
  const grouped = new Map();
  for (const entry of ledgerRawEntries.value) {
    const projectID = extractProjectID(entry);
    if (!projectID) continue;
    const project = ledgerProjectIndex.value.get(projectID);
    const current = grouped.get(projectID) || {
      initial: projectInitialFor(project?.title || projectID),
      tone: projectToneFor(projectID),
      title: project?.title || `Project ${projectID.slice(-6)}`,
      company: project?.company_name || project?.client_name || 'MergeOS client',
      escrowCents: 0,
      contributors: 0,
      prs: 0,
    };
    if (entry.type === 'payment_verified') {
      current.escrowCents += Number(entry.amount_cents) || 0;
    }
    if (entry.type === 'task_reserve') {
      current.contributors += 1;
    }
    if (entry.type === 'task_payment') {
      current.prs += 1;
    }
    grouped.set(projectID, current);
  }
  return Array.from(grouped.values()).slice(0, 4).map((project) => ({
    ...project,
    escrow: `${formatLedgerMRGFromCents(project.escrowCents)} Escrow`,
  }));
});
