    const proofLabel = latest?.rawContractReference
      ? `Contract ${shortLedgerHash(latest.rawContractReference)}`
      : (latest?.rawReference ? shortLedgerReference(latest.rawReference) : 'Proof pending');
    return {
      ...contract,
      count: rows.length,
      contextURL: protocolManifestURL.value,
      filterActionLabel: rows.length ? 'Filter timeline' : 'Waiting',
      filterLabel: latest?.typeLabel || contract.fallbackFilter,
      latestEvent: latest,
      latestLabel: latest ? `${latest.typeLabel} / ${latest.project} / ${latest.time}` : 'Waiting for event',
      latestReference,
      proofLabel,
      sourceLabel: contract.sourcePath,
      sourceURL: absolutePublicPath(contract.sourcePath),
      status: rows.length ? `${rows.length} live` : 'Waiting',
      statusTone: rows.length ? contract.tone : 'slate',
    };
  }),
);

