const liveFeedRealtimeStatus = computed(() => {
  const when = wsLastEventAt.value ? formatLedgerDateTime(wsLastEventAt.value).time : '';
  switch (wsConnectionState.value) {
  case 'synced':
    return { label: 'Realtime synced', detail: when ? `Synced ${when}` : 'Synced', tone: 'green' };
  case 'connected':
    return { label: 'Realtime live', detail: when ? `Live ${when}` : 'Live', tone: 'green' };
  case 'connecting':
    return { label: 'Connecting', detail: 'Connecting', tone: 'blue' };
  case 'reconnecting':
    return { label: 'Reconnecting', detail: wsReconnectDelayMs.value ? `Retry ${Math.round(wsReconnectDelayMs.value / 1000)}s` : 'Retrying', tone: 'amber' };
  default:
    return { label: 'Realtime idle', detail: 'Waiting', tone: 'slate' };
  }
});

