    body: item.body,
    meta: item.meta,
    tone: item.tone === 'green' || item.tone === 'blue' ? item.tone : 'blue',
    createdAt: item.createdAt,
  }));
  const ledgerRows = ledgerEventItems.value.slice(0, 4).map(mapLedgerTransparencyEvent).map((event) => ({
    id: `ledger-${event.key}`,
    subject: event.type,
    body: `${event.project} recorded ${event.amount}.`,
    meta: event.time,
    tone: event.tone === 'green' || event.tone === 'blue' ? event.tone : 'blue',
    createdAt: event.createdAt,
  }));
  const rows = [...actionRows, ...liveRows, ...ledgerRows].sort((a, b) => new Date(b.createdAt || 0) - new Date(a.createdAt || 0));
  if (rows.length) return rows;
  return [{
    id: 'empty-public-notification',
    subject: marketplaceLoading.value ? 'Loading platform updates' : 'No live updates yet',
    body: marketplaceLoading.value ? 'Fetching the latest ledger and marketplace status.' : 'Funding, marketplace, and ledger activity will appear here.',
    meta: marketplaceLoading.value ? 'Syncing' : 'Waiting for activity',
    tone: 'blue',
    createdAt: new Date(0).toISOString(),
  }];
});

const protocolManifestURL = computed(() => absolutePublicPath(publicProtocolManifestPath));
const protocolManifestView = computed(() => protocolManifest.value && typeof protocolManifest.value === 'object' ? protocolManifest.value : {});
const protocolDocumentRowsRaw = computed(() => Array.isArray(protocolManifestView.value.documents) ? protocolManifestView.value.documents : []);
const protocolEndpointRowsRaw = computed(() => Array.isArray(protocolManifestView.value.endpoints) ? protocolManifestView.value.endpoints : []);
const protocolAgentContextMap = computed(() => {
  const context = protocolManifestView.value.agent_context?.context_urls;
  return context && typeof context === 'object' ? context : {};
});
const protocolRunbookRaw = computed(() => {
