function localizedMenuItems(items = [], translations = {}) {
  return items.map((item) => {
    let localized = translations[item.title] || [];
    if (item.title === 'MergeIDE') {
      localized = ['MergeIDE', publicMergeIdeCopy.value.homeBody];
    }
    if (item.title === 'System vision') {
      localized = publicSystemNavTranslations[activeLocale.value] || publicSystemNavTranslations['en-US'];
    }
    return {
      ...item,
      title: localized[0] || item.title,
      body: localized[1] || item.body,
    };
  });
}

