const publicCustomerCommandCopy = computed(() =>
  publicCustomerCommandTranslations[activeLocale.value] || publicCustomerCommandTranslations['en-US'],
);

function publicCustomerActivityCount(needles = []) {
  const pattern = new RegExp(needles.join('|'), 'i');
  return liveFeedAllItemsView.value.filter((item) =>
    pattern.test([
      item.rawType,
      item.typeLabel,
      item.title,
      item.body,
      item.project,
      item.status,
    ].filter(Boolean).join(' ')),
  ).length;
}

const publicCustomerCommandStats = computed(() => {
  const stats = marketplaceStats.value;
  const copy = publicCustomerCommandCopy.value.stats;
  const projectCount = Number(stats.project_count) || (marketplaceData.value.projects || []).length || marketplaceProjectsView.value.length;
  const openTasks = Number(stats.open_task_count) || (marketplaceData.value.bounties || []).length || marketplaceBountiesView.value.length;
  const escrowCents = Number(stats.total_budget_cents) || publicVerifiedFundingCents.value;
  const aiSignals = publicCustomerActivityCount(['ai', 'agent', 'scan', 'review']);
  return [
    { label: copy.projects, value: String(projectCount), caption: copy.projectsCaption, icon: LayoutDashboard, tone: 'blue' },
    { label: copy.tasks, value: String(openTasks), caption: copy.tasksCaption, icon: ListTodo, tone: 'green' },
    { label: copy.escrow, value: formatPublicMRGFromCents(escrowCents), caption: copy.escrowCaption, icon: CircleDollarSign, tone: 'amber' },
    { label: copy.ai, value: String(aiSignals), caption: copy.aiCaption, icon: Bot, tone: 'purple' },
  ];
});

const publicCustomerControlRows = computed(() => {
  const copy = publicCustomerCommandCopy.value;
  const signalCopy = copy.signals;
  const projects = Number(marketplaceStats.value.project_count) || (marketplaceData.value.projects || []).length || marketplaceProjectsView.value.length;
  const openTasks = Number(marketplaceStats.value.open_task_count) || (marketplaceData.value.bounties || []).length || marketplaceBountiesView.value.length;
  const escrow = formatPublicMRGFromCents(Number(marketplaceStats.value.total_budget_cents) || publicVerifiedFundingCents.value);
  const prSignals = publicCustomerActivityCount(['pull', 'pr', 'review', 'deploy']);
  const aiSignals = publicCustomerActivityCount(['ai', 'agent', 'scan', 'review']);
  const proofRows = ledgerEventItems.value.length || liveFeedAllItemsView.value.length;
  const definitions = [
    { key: 'overview', icon: LayoutDashboard, tone: 'blue', signal: `${projects} ${signalCopy.projects}` },
    { key: 'escrow', icon: CircleDollarSign, tone: 'green', signal: `${escrow} ${signalCopy.escrow}` },
    { key: 'tasks', icon: ListTodo, tone: 'purple', signal: `${openTasks} ${signalCopy.tasks}` },
    { key: 'prs', icon: GitPullRequest, tone: 'blue', signal: `${prSignals} ${signalCopy.pr}` },
    { key: 'ai', icon: Bot, tone: 'purple', signal: `${aiSignals} ${signalCopy.ai}` },
    { key: 'proof', icon: ShieldCheck, tone: 'amber', signal: `${proofRows} ${signalCopy.proof}` },
  ];
  return definitions.map((definition, index) => {
    const row = copy.controls[index] || [];
    return {
      ...definition,
      title: row[0] || definition.key,
      body: row[1] || '',
    };
  });
});

const publicCustomerLiveRows = computed(() => {
  const copy = publicCustomerCommandCopy.value.signals;
  const projects = (marketplaceData.value.projects || [])
    .map(mapMarketplaceProject)
    .slice(0, 2)
    .map((project) => ({
      id: `project-${project.id}`,
      icon: project.icon,
      tone: project.urgent ? 'green' : 'blue',
      title: project.title,
      body: project.body,
      meta: `${project.budget} / ${project.taskLabel}`,
      status: project.badge || copy.projectStatus,
      statusTone: project.urgent ? 'green' : 'blue',
    }));
  const bounties = (marketplaceData.value.bounties || [])
    .map(mapMarketplaceBounty)
    .slice(0, 2)
    .map((task) => ({
      id: `task-${task.id}`,
      icon: task.icon,
      tone: task.tone,
      title: task.title,
      body: task.acceptance,
      meta: `${task.reward} / ${task.lane} / ${task.issue}`,
      status: copy.taskStatus,
      statusTone: 'amber',
    }));
  return [...projects, ...bounties].slice(0, 4);
});

const publicCustomerProofRows = computed(() => {
  const ledgerRows = ledgerEventItems.value.slice(0, 4).map(mapLedgerTransparencyEvent).map((event) => ({
    key: `ledger-${event.key}`,
    icon: event.icon,
    tone: event.tone,
    title: event.type,
    body: `${event.project} / ${event.status}`,
    reference: event.auditLabel || event.ref,
    amount: event.amount,
    amountTone: event.amountTone || 'neutral',
  }));
  if (ledgerRows.length) return ledgerRows;
  return liveFeedAllItemsView.value.slice(0, 4).map((event) => ({
    key: `live-${event.id}`,
    icon: event.icon,
    tone: event.tone,
    title: event.typeLabel,
    body: `${event.project} / ${event.status}`,
    reference: event.reference || event.auditLabel || event.date,
    amount: event.amount || event.status,
    amountTone: event.amount ? 'positive' : 'neutral',
  }));
});

