function upsertSeoElement(selector, createElement) {
  let element = document.head.querySelector(selector);
  if (!element) {
    element = createElement();
    document.head.appendChild(element);
  }
  return element;
}

function setSeoMeta(selector, attributes = {}) {
  const element = upsertSeoElement(selector, () => {
    const meta = document.createElement('meta');
    meta.dataset.mergeosSeo = attributes['data-mergeos-seo'] || '';
    return meta;
  });
  Object.entries(attributes).forEach(([key, value]) => {
    if (value === undefined || value === null) return;
    if (key === 'data-mergeos-seo') {
      element.dataset.mergeosSeo = value;
      return;
    }
    element.setAttribute(key, String(value));
  });
}

function setSeoLink(selector, attributes = {}) {
  const element = upsertSeoElement(selector, () => {
    const link = document.createElement('link');
    link.dataset.mergeosSeo = attributes['data-mergeos-seo'] || '';
    return link;
  });
  Object.entries(attributes).forEach(([key, value]) => {
    if (value === undefined || value === null) return;
    if (key === 'data-mergeos-seo') {
      element.dataset.mergeosSeo = value;
      return;
    }
    element.setAttribute(key, String(value));
  });
}

function applySeoToDocument() {
  if (!hasWindow) return;
  const seo = getSeoDataForPath(publicPathForPage(publicPage.value), {
    origin: window.location.origin,
    locale: seoLocaleMap[activeLocale.value] || 'en_US',
  });
  document.title = seo.title;
  setSeoMeta('meta[data-mergeos-seo="description"]', { 'data-mergeos-seo': 'description', name: 'description', content: seo.description });
  setSeoMeta('meta[data-mergeos-seo="keywords"]', { 'data-mergeos-seo': 'keywords', name: 'keywords', content: seo.keywords.join(', ') });
  setSeoMeta('meta[data-mergeos-seo="robots"]', { 'data-mergeos-seo': 'robots', name: 'robots', content: seo.robots });
  setSeoLink('link[data-mergeos-seo="canonical"]', { 'data-mergeos-seo': 'canonical', rel: 'canonical', href: seo.canonical });
  document.head.querySelectorAll('link[data-mergeos-seo="alternate"]').forEach((link) => link.remove());
  for (const lang of ['en', 'vi', 'zh-Hans', 'ja', 'ko', 'x-default']) {
    const link = document.createElement('link');
    link.dataset.mergeosSeo = 'alternate';
    link.rel = 'alternate';
    link.hreflang = lang;
    link.href = seo.canonical;
    document.head.appendChild(link);
  }
  setSeoMeta('meta[data-mergeos-seo="og:site_name"]', { 'data-mergeos-seo': 'og:site_name', property: 'og:site_name', content: 'MergeOS' });
  setSeoMeta('meta[data-mergeos-seo="og:type"]', { 'data-mergeos-seo': 'og:type', property: 'og:type', content: seo.type });
  setSeoMeta('meta[data-mergeos-seo="og:title"]', { 'data-mergeos-seo': 'og:title', property: 'og:title', content: seo.title });
  setSeoMeta('meta[data-mergeos-seo="og:description"]', { 'data-mergeos-seo': 'og:description', property: 'og:description', content: seo.description });
  setSeoMeta('meta[data-mergeos-seo="og:url"]', { 'data-mergeos-seo': 'og:url', property: 'og:url', content: seo.canonical });
  setSeoMeta('meta[data-mergeos-seo="og:image"]', { 'data-mergeos-seo': 'og:image', property: 'og:image', content: seo.image });
  setSeoMeta('meta[data-mergeos-seo="twitter:card"]', { 'data-mergeos-seo': 'twitter:card', name: 'twitter:card', content: 'summary_large_image' });
  setSeoMeta('meta[data-mergeos-seo="twitter:title"]', { 'data-mergeos-seo': 'twitter:title', name: 'twitter:title', content: seo.title });
  setSeoMeta('meta[data-mergeos-seo="twitter:description"]', { 'data-mergeos-seo': 'twitter:description', name: 'twitter:description', content: seo.description });
  setSeoMeta('meta[data-mergeos-seo="twitter:image"]', { 'data-mergeos-seo': 'twitter:image', name: 'twitter:image', content: seo.image });
  const script = upsertSeoElement('script[data-mergeos-seo="jsonld"]', () => {
    const item = document.createElement('script');
    item.dataset.mergeosSeo = 'jsonld';
    item.type = 'application/ld+json';
    return item;
  });
  script.textContent = JSON.stringify(seo.structuredData);
}

