function formatTokenWorkflowResult(result = {}) {
  const id = result.claim_id || result.reservation_id || 'workflow';
  const amount = result.allocation_mrg || result.reserve_mrg || result.ledger_entry?.amount_cents || 0;
  const sequence = result.ledger_entry?.sequence ? `ledger #${result.ledger_entry.sequence}` : 'ledger receipt';
  return `${id} / ${formatMRG(amount)} / ${toTitleLabel(result.status || 'pending review')} / ${sequence}`;
}

async function copyTokenWorkflowHash(result = {}) {
  const hash = result.ledger_entry?.entry_hash || '';
  if (!hash) {
    showToast('No ledger hash available yet.');
    return;
  }
  const copied = await copyTextToClipboard(hash);
  showToast(copied ? 'Ledger hash copied.' : `Ledger hash ${shortLedgerHash(hash)}`);
}

function navContextMenuInlineStyle(menu) {
  if (navContextGeometry.value.menu !== menu) return {};
  return {
    '--nav-context-left': `${navContextGeometry.value.left}px`,
    '--nav-context-top': `${navContextGeometry.value.top}px`,
    '--nav-context-width': `${navContextGeometry.value.width}px`,
    '--nav-context-anchor-left': `${navContextGeometry.value.anchorLeft}px`,
  };
}

function measureNavContextMenu(menu, event = {}) {
  if (!hasWindow) return;
  const source = event?.currentTarget;
  const container = source?.closest?.('.nav-menu') || source;
  const trigger = container?.querySelector?.('.nav-menu-trigger') || source;
  if (!trigger?.getBoundingClientRect) return;

  const rect = trigger.getBoundingClientRect();
  const headerRoot = trigger.closest?.('.home-navbar, .project-flow-navbar');
  const shellElement = trigger.closest?.('.nav-inner')
    || headerRoot?.querySelector?.('.nav-inner')
    || headerRoot;
  const shellRect = shellElement?.getBoundingClientRect?.();
  const viewportWidth = window.innerWidth || document.documentElement.clientWidth || 1024;
  const viewportGutter = viewportWidth < 720 ? 12 : viewportWidth < 1120 ? 14 : 18;
  const safeLeft = viewportGutter;
  const safeRight = viewportWidth - viewportGutter;
  const shellStyles = shellElement ? window.getComputedStyle(shellElement) : null;
  const shellPaddingLeft = Number.parseFloat(shellStyles?.paddingLeft || '0') || 0;
  const shellPaddingRight = Number.parseFloat(shellStyles?.paddingRight || '0') || 0;
  const contentLeft = Math.max(safeLeft, Math.round((shellRect?.left ?? 0) + shellPaddingLeft));
  const contentRight = Math.min(safeRight, Math.round((shellRect?.right ?? viewportWidth) - shellPaddingRight));
  const shellWidth = Math.max(320, contentRight - contentLeft);
  const availableWidth = Math.max(320, safeRight - safeLeft);
  const maxDesktopWidth = menu === 'product' ? 1080 : 920;
  const maxTabletWidth = menu === 'product' ? 940 : 860;
  const targetWidth = viewportWidth < 1120 ? maxTabletWidth : maxDesktopWidth;
  const width = viewportWidth < 720 ? availableWidth : Math.min(shellWidth, availableWidth, targetWidth);
  const centeredLeft = Math.round(contentLeft + ((shellWidth - width) / 2));
  const left = viewportWidth < 720
    ? safeLeft
    : Math.min(Math.max(safeLeft, centeredLeft), Math.max(safeLeft, safeRight - width));
  const headerBottom = Math.max(shellRect?.bottom ?? 0, rect.bottom);
  const top = Math.max(56, Math.round(headerBottom + 2));
  const anchorLeft = Math.min(Math.max(28, Math.round(rect.left + rect.width / 2 - left)), width - 28);

  navContextGeometry.value = {
    menu,
    left,
    top,
    width,
    anchorLeft,
  };
}

function openNavContextMenu(menu, event = {}) {
  cancelNavContextClose();
  if (pinnedNavMenu.value && pinnedNavMenu.value !== menu) {
    pinnedNavMenu.value = '';
  }
  measureNavContextMenu(menu, event);
  activeNavMenu.value = menu;
}

function toggleNavContextMenu(menu, event = {}) {
  cancelNavContextClose();
  if (activeNavMenu.value === menu && pinnedNavMenu.value === menu) {
    closeNavContextMenu();
    return;
  }
  measureNavContextMenu(menu, event);
  activeNavMenu.value = menu;
  pinnedNavMenu.value = menu;
}

function closeNavContextMenu() {
  cancelNavContextClose();
  activeNavMenu.value = '';
  pinnedNavMenu.value = '';
}

function scheduleNavContextClose() {
  cancelNavContextClose();
  if (pinnedNavMenu.value && pinnedNavMenu.value === activeNavMenu.value) return;
  if (!hasWindow) {
    closeNavContextMenu();
    return;
  }
  navContextCloseTimer = window.setTimeout(() => {
    navContextCloseTimer = 0;
    activeNavMenu.value = '';
  }, 900);
}

function cancelNavContextClose() {
  if (!navContextCloseTimer || !hasWindow) return;
  window.clearTimeout(navContextCloseTimer);
  navContextCloseTimer = 0;
}

function handleNavContextOutsideClick(event) {
  if (!activeNavMenu.value) return;
  const target = event.target;
  if (target?.closest?.('.nav-menu, .locale-menu, .account-menu')) return;
  closeNavContextMenu();
  const activeElement = document.activeElement;
  if (activeElement?.closest?.('.nav-menu, .locale-menu, .account-menu')) {
    activeElement.blur();
  }
}

function openLegalPageFromAuth(page = 'terms') {
  const legalPage = page === 'privacy' ? 'privacy' : 'terms';
  const targetPath = publicPathForPage(legalPage);
  if (hasWindow) {
    const url = new URL(targetPath, window.location.origin);
    window.open(url.toString(), '_blank', 'noopener,noreferrer');
    return;
  }
  openPublicPage(legalPage);
}

function openDashboard() {
  publicModeVisible.value = false;
  dashboardSection.value = 'projects';
  dashboardProjectFocus.value = 'overview';
  if (user.value) {
    void loadDashboardData({ silent: true });
    void loadWorkerDashboardData({ silent: true });
  }
  if (!hasWindow) return;
  window.requestAnimationFrame(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  });
}

function normalizeDashboardProjectFocus(focus = 'overview') {
  return ['overview', 'list', 'tasks', 'ai-logs', 'activity', 'settings'].includes(focus) ? focus : 'overview';
}

function dashboardProjectFocusElement(focus = dashboardProjectFocus.value) {
  switch (normalizeDashboardProjectFocus(focus)) {
  case 'list':
    return dashboardProjectListPanel.value;
  case 'tasks':
    return dashboardTasksPanel.value;
  case 'ai-logs':
    return dashboardAILogsPanel.value;
  case 'activity':
    return dashboardActivityPanel.value;
  default:
    return dashboardProjectHeader.value;
  }
}

function focusDashboardProjectArea(focus = dashboardProjectFocus.value) {
  if (!hasWindow) return;
  const targetFocus = normalizeDashboardProjectFocus(focus);
  void nextTick().then(() => {
    window.requestAnimationFrame(() => {
      const target = dashboardProjectFocusElement(targetFocus);
      if (!target) {
        window.scrollTo({ top: 0, behavior: 'smooth' });
        return;
      }
      target.scrollIntoView({ behavior: 'smooth', block: 'start' });
      target.focus?.({ preventScroll: true });
    });
  });
}

async function selectDashboardProject(projectID) {
  if (!projectID) return;
  dashboardProjectActionsVisible.value = false;
  selectedDashboardProjectID.value = projectID;
  void loadDashboardDeliverySnapshotData(projectID, { silent: true });
  await nextTick();
  if (!hasWindow) return;
